async (params, browser) => {
  // Open user profile
  await browser.open(`https://www.kaggle.com/${params.username}`)

  // Wait for profile page
  await browser.waitForSelector('h1, [role=\'main\'], img[alt]', 15000)

  // Let profile render
  await browser.wait(3000)

  // Scroll for more info
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract profile data
  const profile_data = await browser.evaluate(`const name = document.querySelector('h1')?.textContent?.trim() || document.title.split('|')[0]?.trim() || ''; const allText = document.body.innerText; const bioEl = document.querySelector('[class*="bio"], [class*="description"], p'); const bio = bioEl ? bioEl.textContent.trim().substring(0, 300) : ''; const tierMatch = allText.match(/(Grandmaster|Master|Expert|Contributor|Novice)/i); const tier = tierMatch ? tierMatch[1] : ''; const datasets = []; const notebooks = []; document.querySelectorAll('a[href*="/datasets/"]').forEach(a => { const text = a.textContent.trim(); if (text && text.length > 3 && text.length < 200) datasets.push({ title: text, url: 'https://www.kaggle.com' + a.getAttribute('href') }); }); document.querySelectorAll('a[href*="/code/"]').forEach(a => { const text = a.textContent.trim(); if (text && text.length > 3 && text.length < 200) notebooks.push({ title: text, url: 'https://www.kaggle.com' + a.getAttribute('href') }); }); const medals = {}; const goldMatch = allText.match(/(\d+)\s*gold/i); const silverMatch = allText.match(/(\d+)\s*silver/i); const bronzeMatch = allText.match(/(\d+)\s*bronze/i); if (goldMatch) medals.gold = goldMatch[1]; if (silverMatch) medals.silver = silverMatch[1]; if (bronzeMatch) medals.bronze = bronzeMatch[1]; return { name, bio, tier, medals, datasets: datasets.slice(0, 5), notebooks: notebooks.slice(0, 5), url: window.location.href };`)

  return profile_data
}
